/** @jsxRuntime classic */
/** @jsx jsx */
import React from 'react';
// eslint-disable-next-line @typescript-eslint/no-unused-vars
import { jsx } from '@universe-design/stylex/react';
import { useCellStylexStyles } from './sx';
import { useDetailsDisplayContext } from './DetailsDisplayContext';
import { useDetailsDisplayItemContext } from './DetailsDisplayItemContext';

const DataCell = ({ children }: { children: React.ReactNode }) => {
  const { align, prefix, size, layout } = useDetailsDisplayContext();
  const { isRowEnd, isColumnEnd, span } = useDetailsDisplayItemContext();
  const alignCenter = align === 'center';
  const alignJustify = align === 'justify';
  const alignStart = align === 'start';
  const inline = layout === 'inline';
  const vertical = layout === 'vertical';
  const styles = useCellStylexStyles({ prefix: `${prefix}__data-cell` });

  return (
    <td
      sx={[
        styles.td,
        alignCenter && styles.align.left,
        alignJustify && styles.align.right,
        alignStart && styles.align.left,
        !isRowEnd && styles.size[size],
        !isColumnEnd && [vertical && styles.layout.verticalGap, !vertical && styles.layout.horizontalGap],
        inline && styles.inlineFlex,
      ]}
      colSpan={span}
    >
      {children}
    </td>
  );
};

export default DataCell;
